opencat.script:
// ===== Scene 1 入场（0s）=====
ctx.fromTo('s1-badge', { opacity: 0, y: -16 }, { opacity: 1, y: 0, duration: 0.5, ease: 'power2.out' });
ctx.fromTo('s1-kicker', { opacity: 0, x: -20 }, { opacity: 1, x: 0, duration: 0.5, delay: 0.1, ease: 'power3.out' });
ctx.fromTo('s1-title', { opacity: 0, y: 40, scale: 0.94 }, { opacity: 1, y: 0, scale: 1, duration: 0.7, delay: 0.15, ease: 'spring.gentle' });
ctx.fromTo('s1-sub', { opacity: 0, y: 18 }, { opacity: 1, y: 0, duration: 0.5, delay: 0.32, ease: 'power2.out' });
ctx.fromTo('s1-lens', { opacity: 0, scale: 0.6 }, { opacity: 1, scale: 1, duration: 0.7, delay: 0.25, ease: 'back.out' });
ctx.fromTo('s1-product', { opacity: 0, scale: 0.5, rotation: -25 }, { opacity: 1, scale: 1, rotation: 0, duration: 0.6, delay: 0.45, ease: 'back.out' });

// ===== Scene 2 入场（3.6s）=====
ctx.fromTo('s2-title', { opacity: 0, y: 30 }, { opacity: 1, y: 0, duration: 0.6, delay: 3.6, ease: 'power3.out' });
ctx.fromTo('s2-lens', { opacity: 0, scale: 0.55 }, { opacity: 1, scale: 1, duration: 0.65, delay: 3.7, ease: 'back.out' });
ctx.fromTo('s2-product', { opacity: 0, scale: 0.6, y: 20 }, { opacity: 1, scale: 1, y: 0, duration: 0.6, delay: 3.9, ease: 'spring.gentle' });
ctx.fromTo(['s2-tag1', 's2-tag2', 's2-tag3'], { opacity: 0, x: -30, scale: 0.8 }, { opacity: 1, x: 0, scale: 1, duration: 0.5, delay: 4.0, stagger: 0.1, ease: 'back.out' });

// ===== Scene 3 入场（7.25s）=====
ctx.fromTo('s3-num', { opacity: 0, scale: 0.6 }, { opacity: 1, scale: 1, duration: 0.6, delay: 7.25, ease: 'back.out' });
ctx.fromTo('s3-kicker', { opacity: 0, x: -20 }, { opacity: 1, x: 0, duration: 0.5, delay: 7.4, ease: 'power3.out' });
ctx.fromTo('s3-title', { opacity: 0, y: 30 }, { opacity: 1, y: 0, duration: 0.6, delay: 7.45, ease: 'spring.gentle' });
ctx.fromTo('s3-desc', { opacity: 0, y: 16 }, { opacity: 1, y: 0, duration: 0.5, delay: 7.6, ease: 'power2.out' });
ctx.fromTo('s3-lens', { opacity: 0, scale: 0.6, x: 40 }, { opacity: 1, scale: 1, x: 0, duration: 0.7, delay: 7.5, ease: 'power3.out' });

// ===== Scene 4 入场（11.15s）=====
ctx.fromTo('s4-lens', { opacity: 0, scale: 0.6 }, { opacity: 1, scale: 1, duration: 0.65, delay: 11.15, ease: 'back.out' });
ctx.fromTo('s4-product', { opacity: 0, rotation: -18, scale: 0.8 }, { opacity: 1, rotation: 0, scale: 1, duration: 0.6, delay: 11.35, ease: 'spring.gentle' });
ctx.fromTo('s4-num', { opacity: 0, y: 20 }, { opacity: 1, y: 0, duration: 0.5, delay: 11.3, ease: 'power3.out' });
ctx.fromTo('s4-title', { opacity: 0, y: 30 }, { opacity: 1, y: 0, duration: 0.6, delay: 11.45, ease: 'spring.gentle' });
ctx.fromTo('s4-desc', { opacity: 0, y: 16 }, { opacity: 1, y: 0, duration: 0.5, delay: 11.6, ease: 'power2.out' });

// ===== Scene 5 入场（15.05s）=====
ctx.fromTo('s5-logo', { opacity: 0, scale: 0.4, rotation: -30 }, { opacity: 1, scale: 1, rotation: 0, duration: 0.7, delay: 15.05, ease: 'back.out' });
ctx.fromTo('s5-brand', { opacity: 0, y: 30 }, { opacity: 1, y: 0, duration: 0.6, delay: 15.25, ease: 'spring.gentle' });
ctx.fromTo('s5-cta', { opacity: 0, y: 20, scale: 0.85 }, { opacity: 1, y: 0, scale: 1, duration: 0.55, delay: 15.4, ease: 'back.out' });
ctx.fromTo('s5-slogan', { opacity: 0 }, { opacity: 1, duration: 0.5, delay: 15.55, ease: 'power2.out' });

// ===== 持续呼吸 / 微运动（ctx.time 全局，只驱动装饰）=====
ctx.to('s1-spark1', { scale: 1.35, opacity: 0.5, duration: 1.6, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s1-spark2', { scale: 1.3, opacity: 0.9, duration: 2.0, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s1-ring', { scale: 1.04, opacity: 0.6, duration: 2.4, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s2-spark1', { scale: 1.3, duration: 1.4, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s2-glow', { scale: 1.08, opacity: 0.9, duration: 3.0, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s3-spark1', { scale: 1.3, duration: 1.8, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s4-glow', { scale: 1.06, duration: 2.8, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s4-spark1', { scale: 1.3, duration: 1.5, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s5-glow', { scale: 1.05, duration: 2.6, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s5-ray1', { opacity: 0.3, duration: 1.2, repeat: -1, yoyo: true, ease: 'sine.inOut' });
ctx.to('s5-ray2', { opacity: 0.3, duration: 1.5, repeat: -1, yoyo: true, ease: 'sine.inOut' });
